// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 1500

// Function to perform DFS and check for cycles
int dfs(int vertex, int *visited, int *path, int **graph, int N) {
    visited[vertex] = 1;
    path[vertex] = 1;
    for (int i = 0; i < N; i++) {
        if (graph[vertex][i] == 1) {
            if (path[i] == 1) return 1; // Cycle detected
            if (visited[i] == 0) {
                if (dfs(i, visited, path, graph, N) == 1) return 1;
            }
        }
    }
    path[vertex] = 0;
    return 0;
}

int main() {
    int N;
    scanf("%d", &N);
    int **graph = (int **)malloc(N * sizeof(int *));
    for (int i = 0; i < N; i++) {
        graph[i] = (int *)malloc(N * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%1d", &graph[i][j]);
        }
    }
    int *visited = (int *)malloc(N * sizeof(int));
    int *path = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        visited[i] = 0;
        path[i] = 0;
    }
    int max_edges = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (graph[i][j] == 0) {
                graph[i][j] = 1;
                if (dfs(i, visited, path, graph, N) == 0) {
                    max_edges++;
                } else {
                    graph[i][j] = 0;
                }
            }
        }
    }
    printf("%d\n", max_edges);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (graph[i][j] == 1) {
                printf("%d %d\n", i + 1, j + 1);
            }
        }
    }
    return 0;
}

