#include <iostream>
#include <vector>
using namespace std;
#define MAXN 1500

// Function to perform DFS and check for cycles
bool dfs(int vertex, vector<bool> &visited, vector<bool> &path, vector<vector<int>> &graph) {
    visited[vertex] = true;
    path[vertex] = true;
    for (int i = 0; i < graph.size(); i++) {
        if (graph[vertex][i] == 1) {
            if (path[i] == true) return true; // Cycle detected
            if (visited[i] == false) {
                if (dfs(i, visited, path, graph) == true) return true;
            }
        }
    }
    path[vertex] = false;
    return false;
}

int main() {
    int N;
    cin >> N;
    vector<vector<int>> graph(N, vector<int>(N, 0));
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            cin >> graph[i][j];
        }
    }
    vector<bool> visited(N, false);
    vector<bool> path(N, false);
    int max_edges = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (graph[i][j] == 0) {
                graph[i][j] = 1;
                if (dfs(i, visited, path, graph) == false) {
                    max_edges++;
                } else {
                    graph[i][j] = 0;
                }
            }
        }
    }
    cout << max_edges << endl;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (graph[i][j] == 1) {
                cout << i + 1 << " " << j + 1 << endl;
            }
        }
    }
    return 0;
}

