import java.util.Scanner;
public class Main {
    static final int MAXN = 1500;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[][] graph = new int[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = sc.nextInt();
            }
        }
        boolean[] visited = new boolean[N];
        boolean[] path = new boolean[N];
        int max_edges = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (graph[i][j] == 0) {
                    graph[i][j] = 1;
                    if (dfs(i, visited, path, graph) == false) {
                        max_edges++;
                    } else {
                        graph[i][j] = 0;
                    }
                }
            }
        }
        System.out.println(max_edges);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (graph[i][j] == 1) {
                    System.out.println((i + 1) + " " + (j + 1));
                }
            }
        }
    }
    public static boolean dfs(int vertex, boolean[] visited, boolean[] path, int[][] graph) {
        visited[vertex] = true;
        path[vertex] = true;
        for (int i = 0; i < graph.length; i++) {
            if (graph[vertex][i] == 1) {
                if (path[i] == true) return true; // Cycle detected
                if (visited[i] == false) {
                    if (dfs(i, visited, path, graph) == true) return true;
                }
            }
        }
        path[vertex] = false;
        return false;
    }
}

